Step 1 вҖ” Ganti type Message di App.tsx
Find:
interface ToolCall { name: string; status: 'running' | 'done' | 'error'; preview?: string; }
interface Message {
  role: 'user' | 'assistant';
  content: string;
  toolCalls?: ToolCall[];
  timestamp: string;
}
Replace:
interface ToolCall { name: string; status: 'running' | 'done' | 'error'; preview?: string; }
type Block =
  | { type: 'text'; text: string }
  | { type: 'tool'; name: string; status: 'running' | 'done' | 'error'; preview?: string };
interface Message {
  role: 'user' | 'assistant';
  content: string;          // user messages tetap pakai ini
  blocks?: Block[];         // assistant pakai ini (interleaved)
  timestamp: string;
}

