              case 'token': {
                const token: string = payload.text;
                setMessages((p) => {
                  const msgs = [...p];
                  const last = msgs[msgs.length - 1];
                  if (last?.role === 'assistant') {
                    // Immutable update вҖ” cegah double-append di React Strict Mode
                    msgs[msgs.length - 1] = { ...last, content: last.content + token };
                  }
                  return msgs;
                });
                break;
              }
Replace:
              case 'token': {
                const token: string = payload.text;
                setMessages((p) => {
                  const msgs = [...p];
                  const last = msgs[msgs.length - 1];
                  if (last?.role === 'assistant') {
                    const blocks = [...(last.blocks || [])];
                    const lastBlock = blocks[blocks.length - 1];
                    if (lastBlock?.type === 'text') {
                      blocks[blocks.length - 1] = { ...lastBlock, text: lastBlock.text + token };
                    } else {
                      blocks.push({ type: 'text', text: token });
                    }
                    msgs[msgs.length - 1] = { ...last, blocks };
                  }
                  return msgs;
                });
                break;
              }

