        {/* Bubble / blocks */}
        {isUser ? (
          <div className="bg-white/[0.07] border border-white/[0.10] text-white/90 rounded-[14px_14px_4px_14px] px-4 py-2.5 text-[14.5px] leading-[1.75]">
            <p className="whitespace-pre-wrap">{message.content}</p>
          </div>
        ) : (
          <div className="flex flex-col gap-2">
            {(message.blocks || []).map((block, bi) =>
              block.type === 'tool' ? (
                <ToolCallGroup key={bi} toolCalls={[{ name: block.name, status: block.status, preview: block.preview }]} />
