                <div key={bi} className="text-white/80 text-[14.5px] leading-[1.75] md-content">
                  <ReactMarkdown
                    remarkPlugins={[remarkGfm]}
                    components={{
                      code({ className, children, ...props }) {
                        const isInline = !className;
